require\('dotenv/config'\);
const pool = new Pool\({ connectionString: process.env.DATABASE_URL }\);
const adapter = new PrismaPg\(pool\);
const prisma = new PrismaClient\({ adapter }\);

prisma.usuario.findUnique\({
  where: { email: 'admin@dogup.com.br' },
  include: { 
    perfil: { include: { permissoes: true } },
    empresa: true
  }
}\).then\(user => {
  console.log\('=== ADMIN USER CHECK ==='\);
  console.log\('Has perfil:', !!user.perfil\);
  console.log\('perfil.isAdmin:', user.perfil?.isAdmin\);
  console.log\('permissoes count:', user.perfil?.permissoes?.length || 0\);
  console.log\('permissoes:', user.perfil?.permissoes?.map\(p => p.codigo\).join\(', '\) || 'none'\);

  // Simulate hasPermission for each permission
  const checks = [
    'MENU_DASHBOARD', 'MENU_CLIENTES', 'MENU_OBRIGACOES', 'MENU_DCTFWEB',
    'MENU_SITUACAO_FISCAL', 'MENU_CERTIDOES', 'MENU_PARCELAMENTOS',
    'MENU_CAIXA_POSTAL', 'MENU_CERTIFICADOS', 'MENU_SIMPLES_NACIONAL',
    'MENU_PER_DCOMP', 'MENU_GERAL_FERRAMENTAS', 'MENU_GERAL_FISCAL', 'MENU_GERAL_OBRIGACOES'
  ];

  console.log\('\\\\n=== PERMISSION CHECKS ==='\);
  for \(const code of checks\) {
    const result = user.perfil?.isAdmin ? true : user.perfil?.permissoes?.some\(p => p.codigo === code\);
    console.log\(code + ':', result ? 'ALLOWED' : 'DENIED'\);
  }

  process.exit\(0\);
}\).catch\(e => { console.error\(e\); process.exit\(1\); }\);
